service-task-definition.script:
// OAuth2 config sample at [OAuth 2.0 Setting]
// - Authorization Endpoint URL: https://login.microsoftonline.com/{your-tenant-id}/oauth2/v2.0/authorize
// - Token Endpoint URL: https://login.microsoftonline.com/{your-tenant-id}/oauth2/v2.0/token
// - Scope: https://graph.microsoft.com/ChannnelMessage.Send offline_access
// - Consumer Key: (Get by Microsoft Azure Active Directory)
// - Consumer Secret: (Get by Microsoft Azure Active Directory)

const GRAPH_URI = 'https://graph.microsoft.com/v1.0/';

const main = () => {
    //// == 工程コンフィグの参照 / Config Retrieving ==
    const oauth2 = configs.getObject('conf_OAuth2');
    const targetUrl = configs.get('conf_TargetUrl');
    const markdownText = configs.get('conf_Markdown') ?? '';

    //// == 演算 / Calculating ==
    const {teamId, channelId, chatId, messageId} = parseTargetUrl(targetUrl);
    const postUrl = post(oauth2, teamId, channelId, chatId, messageId, markdownText);

    //// == ワークフローデータへの代入 / Data Updating ==
    saveData('conf_PostUrl', postUrl);
};

/**
 * 投稿先の URL をパースし、種類に応じて teamId, channelId, chatId, messageId を返す
 * チャットに「メッセージへの返信」は存在しないので本アイテムでは「チャットメッセージ URL」をサポートしなくても良いが、
 * 仕様のわかりやすさのためにサポートしている
 * ----
 * チャンネル URL: https://{domain}/{path}/channel/{channelId}/{channelName}?groupId={teamId}&tenantId={tenantId}
 * チャット URL: https://{domain}/{path}/chat/{chatId}/conversations
 * チャンネルメッセージ URL: https://{domain}/{path}/message/{channelId}/{messageId}?...&groupId={teamId}&...
 * チャットメッセージ URL: https://{domain}/{path}/message/{chatId}/{messageId}?context={"contextType":"chat"}
 * ----
 * @param {String} targetUrl
 * @returns {Object} teamId, channelId, chatId, messageId
 */
const parseTargetUrl = (targetUrl) => {
    const [pathPart, queryPart] = targetUrl.split('?');
    const pathSegments = pathPart.split('/');
    const queryParams = parseQueryParams(queryPart);

    // メッセージ URL の判定
    const messageIndex = pathSegments.indexOf('message');
    if (messageIndex !== -1 && messageIndex + 2 < pathSegments.length) {
        const firstId = decodeURIComponent(pathSegments[messageIndex + 1]);
        const messageId = decodeURIComponent(pathSegments[messageIndex + 2]);
        // groupId があればチャンネルメッセージ、なければチャットメッセージ
        const teamId = queryParams.groupId;
        if (teamId !== undefined) {
            engine.log(`teamId: ${teamId}, channelId: ${firstId}, messageId: ${messageId}`);
            return { teamId, channelId: firstId, chatId: null, messageId };
        }
        engine.log(`chatId: ${firstId}, messageId: ${messageId}`);
        return { teamId: null, channelId: null, chatId: firstId, messageId };
    }

    // チャット URL の判定
    const chatIndex = pathSegments.indexOf('chat');
    if (chatIndex !== -1 && chatIndex + 1 < pathSegments.length) {
        const chatId = decodeURIComponent(pathSegments[chatIndex + 1]);
        engine.log(`chatId: ${chatId}`);
        return { teamId: null, channelId: null, chatId, messageId: null };
    }

    // チャンネル URL の判定
    const channelIndex = pathSegments.indexOf('channel');
    if (channelIndex === -1 || channelIndex + 1 >= pathSegments.length) {
        throw new Error(`Invalid URL: ${targetUrl}`);
    }
    const channelId = decodeURIComponent(pathSegments[channelIndex + 1]);
    const teamId = queryParams.groupId;
    if (teamId === undefined) {
        throw new Error(`groupId not found in URL: ${targetUrl}`);
    }
    engine.log(`teamId: ${teamId}, channelId: ${channelId}`);
    return { teamId, channelId, chatId: null, messageId: null };
};

/**
 * クエリ文字列をパースしてオブジェクトにする
 * @param {String|undefined} queryPart
 * @returns {Object}
 */
const parseQueryParams = (queryPart) => {
    if (queryPart === undefined) {
        return {};
    }
    const params = {};
    queryPart.split('&').forEach(param => {
        const [key, ...rest] = param.split('=');
        params[key] = rest.join('='); // value に = が含まれる場合を考慮
    });
    return params;
};

/**
 * メッセージを投稿する
 * @param {AuthSettingWrapper} oauth2  OAuth2 設定情報
 * @param {String|null} teamId
 * @param {String|null} channelId
 * @param {String|null} chatId
 * @param {String|null} messageId
 * @param {String} markdownText
 * @returns {String} 投稿したメッセージの URL
 */
const post = (oauth2, teamId, channelId, chatId, messageId, markdownText) => {
    let url;
    if (chatId !== null) { // チャットへの投稿（messageId は無視）
        url = `${GRAPH_URI}chats/${encodeURIComponent(chatId)}/messages`;
    } else if (messageId !== null) { // チャンネルメッセージへの返信
        url = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages/${encodeURIComponent(messageId)}/replies`;
    } else { // チャンネルへの投稿
        url = `${GRAPH_URI}teams/${encodeURIComponent(teamId)}/channels/${encodeURIComponent(channelId)}/messages`;
    }
    const body = {
        body: {
            contentType: 'html',
            content: markdown.toHtml(markdownText)
        }
    };
    const response = httpClient.begin()
        .authSetting(oauth2)
        .body(JSON.stringify(body), 'application/json; charset=UTF-8')
        .post(url);
    const status = response.getStatusCode();
    const responseStr = response.getResponseAsString();
    if (status !== 201) {
        engine.log(responseStr);
        throw new Error(`Failed to post message. status: ${status}`);
    }
    return JSON.parse(responseStr).webUrl;
};

/**
 * データ項目への保存
 * @param {String} configName
 * @param {*} data
 */
const saveData = (configName, data) => {
    const def = configs.getObject(configName);
    if (def === null) {
        return;
    }
    engine.setData(def, data);
};
